#!/usr/bin/env node
/**
 * Generates prisma/schema.postgres.prisma from prisma/schema.prisma by
 * swapping the provider line. We don't check the generated file in — it
 * would just drift. Run this every time you want to migrate the postgres
 * variant.
 *
 * Usage:
 *   node scripts/gen-postgres-schema.mjs
 *
 * Then:
 *   npx prisma db push --schema=./prisma/schema.postgres.prisma
 */
import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const here = path.dirname(fileURLToPath(import.meta.url));
const src = path.join(here, "..", "prisma", "schema.prisma");
const dst = path.join(here, "..", "prisma", "schema.postgres.prisma");

const original = await readFile(src, "utf8");

if (!/provider\s*=\s*"sqlite"/.test(original)) {
  console.error("could not find sqlite provider line in", src);
  process.exit(1);
}

const swapped = original
  .replace(/provider\s*=\s*"sqlite"/, 'provider = "postgresql"')
  .replace(
    /^\/\/ Homelab Control Center — Prisma schema[\s\S]*?\n\n/m,
    `// Homelab Control Center — Prisma schema (POSTGRES VARIANT)\n// Generated by scripts/gen-postgres-schema.mjs — DO NOT EDIT BY HAND.\n// Source of truth: prisma/schema.prisma\n\n`,
  );

await writeFile(dst, swapped, "utf8");
console.log(`wrote ${path.relative(process.cwd(), dst)}`);
